//
// IDataNodeRPCService service processor
//

/// END: Used for EXPLAIN ANALYZE
/// 
pub trait IDataNodeRPCServiceSyncHandler {
  /// dispatch FragmentInstance to remote node for query request
  fn handle_send_fragment_instance(&self, req: TSendFragmentInstanceReq) -> thrift::Result<TSendFragmentInstanceResp>;
  /// dispatch PlanNodes in batches to remote node for write request in order to save resource
  fn handle_send_batch_plan_node(&self, req: TSendBatchPlanNodeReq) -> thrift::Result<TSendBatchPlanNodeResp>;
  fn handle_fetch_fragment_instance_info(&self, req: TFetchFragmentInstanceInfoReq) -> thrift::Result<TFragmentInstanceInfoResp>;
  fn handle_cancel_query(&self, req: TCancelQueryReq) -> thrift::Result<TCancelResp>;
  fn handle_cancel_plan_fragment(&self, req: TCancelPlanFragmentReq) -> thrift::Result<TCancelResp>;
  fn handle_cancel_fragment_instance(&self, req: TCancelFragmentInstanceReq) -> thrift::Result<TCancelResp>;
  fn handle_fetch_schema(&self, req: TSchemaFetchRequest) -> thrift::Result<TSchemaFetchResponse>;
  fn handle_send_ts_file_piece_node(&self, req: TTsFilePieceReq) -> thrift::Result<TLoadResp>;
  fn handle_send_load_command(&self, req: TLoadCommandReq) -> thrift::Result<TLoadResp>;
  fn handle_update_attribute(&self, req: TAttributeUpdateReq) -> thrift::Result<common::TSStatus>;
  /// Config node will create a schema region on a list of data nodes.
  /// 
  /// @param data nodes of the schema region, and schema region id generated by config node
  fn handle_create_schema_region(&self, req: TCreateSchemaRegionReq) -> thrift::Result<common::TSStatus>;
  /// Config node will create a data region on a list of data nodes.
  /// 
  /// @param data nodes of the data region, and data region id generated by config node
  fn handle_create_data_region(&self, req: TCreateDataRegionReq) -> thrift::Result<common::TSStatus>;
  /// Config node will invalidate Partition Info cache.
  /// 
  /// @param bool:isStorageGroup, string:fullPath
  fn handle_invalidate_partition_cache(&self, req: TInvalidateCacheReq) -> thrift::Result<common::TSStatus>;
  /// Config node will invalidate last cache.
  /// 
  /// @param string:database(without root)
  fn handle_invalidate_last_cache(&self, database: String) -> thrift::Result<common::TSStatus>;
  /// Config node will invalidate Schema Info cache.
  /// 
  /// @param bool:isStorageGroup, string:fullPath
  fn handle_invalidate_schema_cache(&self, req: TInvalidateCacheReq) -> thrift::Result<common::TSStatus>;
  /// Config node will delete a data/schema region of a certain storageGroup.
  /// 
  /// @param data nodes of the data region, and data region id generated by config node
  fn handle_delete_region(&self, consensus_group_id: common::TConsensusGroupId) -> thrift::Result<common::TSStatus>;
  /// Change the leader of specified RegionGroup to another DataNode
  /// 
  /// @param The specified RegionGroup and the new leader DataNode
  fn handle_change_region_leader(&self, req: TRegionLeaderChangeReq) -> thrift::Result<TRegionLeaderChangeResp>;
  /// Create a new Region peer in the given DataNode for the specified RegionGroup
  /// 
  /// @param TCreatePeerReq which contains RegionId and its colleagues' locations
  fn handle_create_new_region_peer(&self, req: TCreatePeerReq) -> thrift::Result<common::TSStatus>;
  /// Add a Region peer to the specified RegionGroup
  /// 
  /// @param TMaintainPeerReq which contains RegionId and the DataNodeLocation that selected to perform the add peer process
  fn handle_add_region_peer(&self, req: TMaintainPeerReq) -> thrift::Result<common::TSStatus>;
  /// Remove a Region peer from the specified RegionGroup
  /// 
  /// @param TMaintainPeerReq which contains RegionId and the DataNodeLocation that selected to perform the remove peer process
  fn handle_remove_region_peer(&self, req: TMaintainPeerReq) -> thrift::Result<common::TSStatus>;
  /// Delete a Region peer in the given ConsensusGroup and all of its data on the specified DataNode
  /// 
  /// @param TMaintainPeerReq which contains RegionId and the DataNodeLocation where the specified Region peer located
  fn handle_delete_old_region_peer(&self, req: TMaintainPeerReq) -> thrift::Result<common::TSStatus>;
  /// Reset a consensus group's peer list
  fn handle_reset_peer_list(&self, req: TResetPeerListReq) -> thrift::Result<common::TSStatus>;
  /// Get the result of a region maintainance task
  fn handle_get_region_maintain_result(&self, task_id: i64) -> thrift::Result<TRegionMigrateResult>;
  /// Notify the DataNode of the beginning or ending the migration of the specified RegionGroup
  fn handle_notify_region_migration(&self, req: TNotifyRegionMigrationReq) -> thrift::Result<common::TSStatus>;
  /// Config node will clean DataNode cache, the Data node will not accept read/write request when disabled
  /// @param data node location
  fn handle_clean_data_node_cache(&self, req: TCleanDataNodeCacheReq) -> thrift::Result<common::TSStatus>;
  /// Config node will stop and clear the Data node.
  fn handle_stop_and_clear_data_node(&self) -> thrift::Result<common::TSStatus>;
  /// ConfigNode will ask DataNode for heartbeat in every few seconds.
  /// 
  /// @param ConfigNode will send the latest config_node_list and load balancing policies in TDataNodeHeartbeatReq
  /// 
  fn handle_get_data_node_heart_beat(&self, req: TDataNodeHeartbeatReq) -> thrift::Result<TDataNodeHeartbeatResp>;
  /// ConfigNode will ask DataNode to update region cache
  /// 
  /// @param ConfigNode will send timestamp and new regionRouteMap in TRegionRouteReq
  /// 
  fn handle_update_region_cache(&self, req: TRegionRouteReq) -> thrift::Result<common::TSStatus>;
  /// Config node will create a function on a list of data nodes.
  /// 
  /// @param function name, function class name, and executable uris
  /// 
  fn handle_create_function(&self, req: TCreateFunctionInstanceReq) -> thrift::Result<common::TSStatus>;
  /// Config node will drop a function on a list of data nodes.
  /// 
  /// @param function name
  /// 
  fn handle_drop_function(&self, req: TDropFunctionInstanceReq) -> thrift::Result<common::TSStatus>;
  /// Config node will create a trigger instance on data node.
  /// 
  /// @param TriggerInformation, jar file.
  /// 
  fn handle_create_trigger_instance(&self, req: TCreateTriggerInstanceReq) -> thrift::Result<common::TSStatus>;
  /// Config node will active a trigger instance on data node.
  /// 
  /// @param trigger name.
  /// 
  fn handle_active_trigger_instance(&self, req: TActiveTriggerInstanceReq) -> thrift::Result<common::TSStatus>;
  /// Config node will inactive a trigger instance on data node.
  /// 
  /// @param trigger name.
  /// 
  fn handle_inactive_trigger_instance(&self, req: TInactiveTriggerInstanceReq) -> thrift::Result<common::TSStatus>;
  /// Config node will drop a trigger on all online config nodes and data nodes.
  /// 
  /// @param trigger name, whether need to delete jar
  /// 
  fn handle_drop_trigger_instance(&self, req: TDropTriggerInstanceReq) -> thrift::Result<common::TSStatus>;
  /// Config node will renew DataNodeLocation of a stateful trigger.
  /// 
  /// @param trigger name, new DataNodeLocation
  /// 
  fn handle_update_trigger_location(&self, req: TUpdateTriggerLocationReq) -> thrift::Result<common::TSStatus>;
  /// Fire a stateful trigger on current data node.
  /// 
  /// @param trigger name, tablet and event
  /// 
  fn handle_fire_trigger(&self, req: TFireTriggerReq) -> thrift::Result<TFireTriggerResp>;
  /// Config node will invalidate permission Info cache.
  /// 
  /// @param string:username, list<string>:roleList
  fn handle_invalidate_permission_cache(&self, req: TInvalidatePermissionCacheReq) -> thrift::Result<common::TSStatus>;
  /// Enable separation of admin powers in datanode
  /// 
  fn handle_enable_separation_of_admin_power(&self) -> thrift::Result<common::TSStatus>;
  /// Config node will create a pipe plugin on a list of data nodes.
  /// 
  /// @param function name, function class name, and executable uris
  /// 
  fn handle_create_pipe_plugin(&self, req: TCreatePipePluginInstanceReq) -> thrift::Result<common::TSStatus>;
  /// Config node will drop a pipe plugin on a list of data nodes.
  /// 
  /// @param function name
  /// 
  fn handle_drop_pipe_plugin(&self, req: TDropPipePluginInstanceReq) -> thrift::Result<common::TSStatus>;
  /// Config node will get built-in services info from data nodes.
  /// 
  fn handle_get_built_in_service(&self) -> thrift::Result<common::TExternalServiceListResp>;
  fn handle_merge(&self) -> thrift::Result<common::TSStatus>;
  fn handle_flush(&self, req: common::TFlushReq) -> thrift::Result<common::TSStatus>;
  fn handle_settle(&self, req: common::TSettleReq) -> thrift::Result<common::TSStatus>;
  fn handle_start_repair_data(&self) -> thrift::Result<common::TSStatus>;
  fn handle_stop_repair_data(&self) -> thrift::Result<common::TSStatus>;
  fn handle_clear_cache(&self, cache_clear_options: BTreeSet<i32>) -> thrift::Result<common::TSStatus>;
  fn handle_show_configuration(&self) -> thrift::Result<common::TShowConfigurationResp>;
  fn handle_show_applied_configurations(&self) -> thrift::Result<common::TShowAppliedConfigurationsResp>;
  fn handle_set_configuration(&self, req: common::TSetConfigurationReq) -> thrift::Result<common::TSStatus>;
  fn handle_load_configuration(&self) -> thrift::Result<common::TSStatus>;
  fn handle_set_system_status(&self, status: String) -> thrift::Result<common::TSStatus>;
  fn handle_kill_query_instance(&self, req: TKillQueryInstanceReq) -> thrift::Result<common::TSStatus>;
  /// Config node will Set the TTL for the database on a list of data nodes.
  fn handle_set_t_t_l(&self, req: common::TSetTTLReq) -> thrift::Result<common::TSStatus>;
  /// Update template cache when template info or template set info is updated
  fn handle_update_template(&self, req: TUpdateTemplateReq) -> thrift::Result<common::TSStatus>;
  /// Construct schema black list in target schemaRegion to block R/W on matched timeseries
  fn handle_construct_schema_black_list(&self, req: TConstructSchemaBlackListReq) -> thrift::Result<common::TSStatus>;
  /// Remove the schema black list to recover R/W on matched timeseries
  fn handle_rollback_schema_black_list(&self, req: TRollbackSchemaBlackListReq) -> thrift::Result<common::TSStatus>;
  /// Config node will invalidate Schema Info cache, which matched by given pathPatternTree.
  /// 
  /// @param binary: pathPatternTree
  fn handle_invalidate_matched_schema_cache(&self, req: TInvalidateMatchedSchemaCacheReq) -> thrift::Result<common::TSStatus>;
  /// Config node will fetch the schema info in black list.
  /// 
  /// @param binary: pathPatternTree
  fn handle_fetch_schema_black_list(&self, req: TFetchSchemaBlackListReq) -> thrift::Result<TFetchSchemaBlackListResp>;
  /// Config node inform this dataNode to execute a distribution data deleion queryengine task
  fn handle_delete_data_for_delete_schema(&self, req: TDeleteDataForDeleteSchemaReq) -> thrift::Result<common::TSStatus>;
  /// Delete matched timeseries and remove according schema black list in target schemRegion
  fn handle_delete_time_series(&self, req: TDeleteTimeSeriesReq) -> thrift::Result<common::TSStatus>;
  /// Alter matched timeseries to specific encoding and compressor in target schemaRegions
  fn handle_alter_encoding_compressor(&self, req: TAlterEncodingCompressorReq) -> thrift::Result<common::TSStatus>;
  /// Alter timeseries measurement
  /// 
  fn handle_alter_time_series_data_type(&self, req: TAlterTimeSeriesReq) -> thrift::Result<common::TSStatus>;
  /// Construct schema black list in target schemaRegion to block R/W on matched timeseries represent by template
  fn handle_construct_schema_black_list_with_template(&self, req: TConstructSchemaBlackListWithTemplateReq) -> thrift::Result<common::TSStatus>;
  /// Remove the schema black list to recover R/W on matched timeseries represent by template
  fn handle_rollback_schema_black_list_with_template(&self, req: TRollbackSchemaBlackListWithTemplateReq) -> thrift::Result<common::TSStatus>;
  /// Deactivate template on device matched by input path pattern
  /// and remove according template schema black list in target schemRegion
  fn handle_deactivate_template(&self, req: TDeactivateTemplateReq) -> thrift::Result<common::TSStatus>;
  fn handle_count_paths_using_template(&self, req: TCountPathsUsingTemplateReq) -> thrift::Result<TCountPathsUsingTemplateResp>;
  fn handle_check_schema_region_using_template(&self, req: TCheckSchemaRegionUsingTemplateReq) -> thrift::Result<TCheckSchemaRegionUsingTemplateResp>;
  fn handle_check_time_series_existence(&self, req: TCheckTimeSeriesExistenceReq) -> thrift::Result<TCheckTimeSeriesExistenceResp>;
  fn handle_construct_view_schema_black_list(&self, req: TConstructViewSchemaBlackListReq) -> thrift::Result<common::TSStatus>;
  fn handle_rollback_view_schema_black_list(&self, req: TRollbackViewSchemaBlackListReq) -> thrift::Result<common::TSStatus>;
  fn handle_delete_view_schema(&self, req: TDeleteViewSchemaReq) -> thrift::Result<common::TSStatus>;
  fn handle_alter_view(&self, req: TAlterViewReq) -> thrift::Result<common::TSStatus>;
  /// Send pipeMetas to DataNodes, for synchronization
  fn handle_push_pipe_meta(&self, req: TPushPipeMetaReq) -> thrift::Result<TPushPipeMetaResp>;
  /// Send one pipeMeta to DataNodes, for create/start/stop/drop one pipe
  fn handle_push_single_pipe_meta(&self, req: TPushSinglePipeMetaReq) -> thrift::Result<TPushPipeMetaResp>;
  /// Send multiple pipeMetas to DataNodes, for create/drop subscriptions
  fn handle_push_multi_pipe_meta(&self, req: TPushMultiPipeMetaReq) -> thrift::Result<TPushPipeMetaResp>;
  /// Send topicMetas to DataNodes, for synchronization
  fn handle_push_topic_meta(&self, req: TPushTopicMetaReq) -> thrift::Result<TPushTopicMetaResp>;
  /// Send one topic meta to DataNodes.
  fn handle_push_single_topic_meta(&self, req: TPushSingleTopicMetaReq) -> thrift::Result<TPushTopicMetaResp>;
  /// Send multiple topic metas to DataNodes, for create/drop subscriptions
  fn handle_push_multi_topic_meta(&self, req: TPushMultiTopicMetaReq) -> thrift::Result<TPushTopicMetaResp>;
  /// Send consumerGroupMetas to DataNodes, for synchronization
  fn handle_push_consumer_group_meta(&self, req: TPushConsumerGroupMetaReq) -> thrift::Result<TPushConsumerGroupMetaResp>;
  /// Send one consumer group meta to DataNodes.
  fn handle_push_single_consumer_group_meta(&self, req: TPushSingleConsumerGroupMetaReq) -> thrift::Result<TPushConsumerGroupMetaResp>;
  /// ConfigNode will ask DataNode for pipe meta in every few seconds
  /// 
  fn handle_pipe_heartbeat(&self, req: TPipeHeartbeatReq) -> thrift::Result<common::TPipeHeartbeatResp>;
  /// Execute CQ on DataNode
  fn handle_execute_c_q(&self, req: TExecuteCQ) -> thrift::Result<common::TSStatus>;
  /// Set space quota
  /// 
  fn handle_set_space_quota(&self, req: common::TSetSpaceQuotaReq) -> thrift::Result<common::TSStatus>;
  /// Set throttle quota
  /// 
  fn handle_set_throttle_quota(&self, req: common::TSetThrottleQuotaReq) -> thrift::Result<common::TSStatus>;
  /// Fetch fragment instance statistics for EXPLAIN ANALYZE
  fn handle_fetch_fragment_instance_statistics(&self, req: TFetchFragmentInstanceStatisticsReq) -> thrift::Result<TFetchFragmentInstanceStatisticsResp>;
  /// Update Table Cache
  fn handle_update_table(&self, req: TUpdateTableReq) -> thrift::Result<common::TSStatus>;
  /// Delete data for drop table, this database is without "root"
  fn handle_invalidate_table_cache(&self, req: TInvalidateTableCacheReq) -> thrift::Result<common::TSStatus>;
  /// Delete data for drop table
  fn handle_delete_data_for_drop_table(&self, req: TDeleteDataOrDevicesForDropTableReq) -> thrift::Result<common::TSStatus>;
  /// Delete devices for drop table
  fn handle_delete_devices_for_drop_table(&self, req: TDeleteDataOrDevicesForDropTableReq) -> thrift::Result<common::TSStatus>;
  /// Invalidate cache for drop column
  fn handle_invalidate_column_cache(&self, req: TInvalidateColumnCacheReq) -> thrift::Result<common::TSStatus>;
  /// Delete column data for drop column
  fn handle_delete_column_data(&self, req: TDeleteColumnDataReq) -> thrift::Result<common::TSStatus>;
  /// Construct table device black list
  fn handle_construct_table_device_black_list(&self, req: TTableDeviceDeletionWithPatternAndFilterReq) -> thrift::Result<common::TSStatus>;
  /// Rollback table device black list
  fn handle_rollback_table_device_black_list(&self, req: TTableDeviceDeletionWithPatternOrModReq) -> thrift::Result<common::TSStatus>;
  /// Delete data for table devices
  fn handle_invalidate_matched_table_device_cache(&self, req: TTableDeviceInvalidateCacheReq) -> thrift::Result<common::TSStatus>;
  /// Delete data for table devices
  fn handle_delete_data_for_table_device(&self, req: TTableDeviceDeletionWithPatternOrModReq) -> thrift::Result<common::TSStatus>;
  /// Delete table devices in black list
  fn handle_delete_table_device_in_black_list(&self, req: TTableDeviceDeletionWithPatternOrModReq) -> thrift::Result<common::TSStatus>;
  /// Get tree device view info for device view
  fn handle_detect_tree_device_view_field_type(&self, req: TDeviceViewReq) -> thrift::Result<TDeviceViewResp>;
  fn handle_submit_test_connection_task(&self, node_locations: common::TNodeLocations) -> thrift::Result<common::TTestConnectionResp>;
  fn handle_submit_internal_test_connection_task(&self, node_locations: common::TNodeLocations) -> thrift::Result<common::TTestConnectionResp>;
  /// Empty rpc, only for connection test
  fn handle_test_connection_empty_r_p_c(&self) -> thrift::Result<common::TSStatus>;
  /// to write audit log or other events as time series *
  fn handle_insert_record(&self, req: client::TSInsertRecordReq) -> thrift::Result<common::TSStatus>;
  /// Write an audit log entry to the DataNode's AuditEventLogger
  fn handle_write_audit_log(&self, req: TAuditLogReq) -> thrift::Result<common::TSStatus>;
}

